// Deep Link Configuration
class DeepLinkConfig {
  static const String scheme = 'myapp';
  static const Set<String> allowedHosts = {
    'profile',
    'payment',
    'settings',
    'home',
  };

  static const Set<String> allowedPaymentActions = {
    'confirm',
    'cancel',
    'status',
  };
}

// Parsed Deep Link Model
class DeepLinkData {
  final String path;
  final Map<String, String> parameters;
  final String? segment1;
  final String? segment2;
  final bool isValid;
  final String? errorMessage;

  const DeepLinkData({
    required this.path,
    required this.parameters,
    this.segment1,
    this.segment2,
    this.isValid = true,
    this.errorMessage,
  });

  factory DeepLinkData.invalid(String message) {
    return DeepLinkData(
      path: '',
      parameters: const {},
      isValid: false,
      errorMessage: message,
    );
  }

  @override
  String toString() =>
      'DeepLinkData(path: $path, segment1: $segment1, segment2: $segment2, params: $parameters, valid: $isValid)';
}

// Deep Link Validator - prevents insecure deep link handling
class DeepLinkValidator {
  // Sanitize string input to prevent injection attacks
  static String? sanitizeInput(String? input) {
    if (input == null || input.isEmpty) return null;

    // Remove any potentially dangerous characters
    final sanitized = input.replaceAll(RegExp(r'[<>"\x27;(){}|\\`]'), '');

    // Limit length to prevent buffer overflow attacks
    if (sanitized.length > 256) {
      return null;
    }

    return sanitized;
  }

  // Validate that the scheme matches our expected scheme
  static bool isValidScheme(Uri uri) {
    return uri.scheme.toLowerCase() == DeepLinkConfig.scheme;
  }

  // Validate that the host/path is in our allowed list
  static bool isAllowedHost(String? host) {
    if (host == null || host.isEmpty) return false;
    return DeepLinkConfig.allowedHosts.contains(host.toLowerCase());
  }

  // Validate profile ID format (numeric only)
  static bool isValidProfileId(String? id) {
    if (id == null || id.isEmpty) return false;
    return RegExp(r'^\d{1,10}$').hasMatch(id);
  }

  // Validate payment action
  static bool isValidPaymentAction(String? action) {
    if (action == null || action.isEmpty) return false;
    return DeepLinkConfig.allowedPaymentActions
        .contains(action.toLowerCase());
  }

  // Validate query parameters - reject suspicious params
  static Map<String, String> validateQueryParameters(
      Map<String, String> params) {
    final validated = <String, String>{};
    for (final entry in params.entries) {
      final key = sanitizeInput(entry.key);
      final value = sanitizeInput(entry.value);
      if (key != null && value != null) {
        // Reject keys that look like injection attempts
        if (!RegExp(r'^[a-zA-Z0-9_-]+$').hasMatch(key)) continue;
        validated[key] = value;
      }
    }
    return validated;
  }

  // Full URL validation
  static DeepLinkData validateAndParse(String? url) {
    if (url == null || url.isEmpty) {
      return DeepLinkData.invalid('Empty URL');
    }

    Uri uri;
    try {
      uri = Uri.parse(url);
    } catch (e) {
      return DeepLinkData.invalid('Malformed URL: $url');
    }

    // Validate scheme
    if (!isValidScheme(uri)) {
      return DeepLinkData.invalid(
          'Invalid scheme: ${uri.scheme}. Expected: ${DeepLinkConfig.scheme}');
    }

    // Extract path segments
    // For myapp://profile/123, host = "profile", pathSegments = ["123"]
    // For myapp://payment/confirm, host = "payment", pathSegments = ["confirm"]
    final host = uri.host.toLowerCase();

    if (!isAllowedHost(host)) {
      return DeepLinkData.invalid('Disallowed path: $host');
    }

    final pathSegments = uri.pathSegments
        .where((s) => s.isNotEmpty)
        .map((s) => sanitizeInput(s))
        .where((s) => s != null)
        .cast<String>()
        .toList();

    final queryParams = validateQueryParameters(uri.queryParameters);

    final fullPath =
        '/$host${pathSegments.isNotEmpty ? '/${pathSegments.join('/')}' : ''}';

    return DeepLinkData(
      path: fullPath,
      parameters: queryParams,
      segment1: host,
      segment2: pathSegments.isNotEmpty ? pathSegments.first : null,
      isValid: true,
    );
  }
}

// Deep Link Handler Service
class DeepLinkHandler {
  static final DeepLinkHandler _instance = DeepLinkHandler._internal();
  factory DeepLinkHandler() => _instance;
  DeepLinkHandler._internal();

  StreamSubscription? _linkSubscription;
  final GlobalKey<NavigatorState> navigatorKey = GlobalKey<NavigatorState>();

  // Rate limiting
  DateTime? _lastDeepLinkTime;
  static const Duration _rateLimitDuration = Duration(seconds: 2);

  // Initialize deep link handling
  Future<void> initialize() async {
    // Handle initial link (app opened via deep link)
    await _handleInitialLink();

    // Handle links while app is running
    _linkSubscription = uriLinkStream.listen(
      (Uri? uri) {
        if (uri != null) {
          _processDeepLink(uri.toString());
        }
      },
      onError: (err) {
        debugPrint('Deep link stream error: $err');
      },
    );
  }

  Future<void> _handleInitialLink() async {
    try {
      final initialLink = await getInitialLink();
      if (initialLink != null) {
        _processDeepLink(initialLink);
      }
    } catch (e) {
      debugPrint('Error getting initial link: $e');
    }
  }

  void _processDeepLink(String url) {
    // Rate limiting to prevent abuse
    final now = DateTime.now();
    if (_lastDeepLinkTime != null &&
        now.difference(_lastDeepLinkTime!) < _rateLimitDuration) {
      debugPrint('Deep link rate limited: $url');
      return;
    }
    _lastDeepLinkTime = now;

    debugPrint('Processing deep link: $url');

    // Validate and parse the deep link
    final deepLinkData = DeepLinkValidator.validateAndParse(url);

    if (!deepLinkData.isValid) {
      debugPrint('Invalid deep link: ${deepLinkData.errorMessage}');
      _showErrorSnackBar('Invalid link received');
      return;
    }

    debugPrint('Parsed deep link: $deepLinkData');

    // Route to appropriate screen
    _routeDeepLink(deepLinkData);
  }

  void _routeDeepLink(DeepLinkData data) {
    final navigator = navigatorKey.currentState;
    if (navigator == null) {
      debugPrint('Navigator not available for deep link routing');
      return;
    }

    switch (data.segment1) {
      case 'profile':
        _handleProfileDeepLink(navigator, data);
        break;
      case 'payment':
        _handlePaymentDeepLink(navigator, data);
        break;
      case 'settings':
        _handleSettingsDeepLink(navigator, data);
        break;
      case 'home':
        navigator.pushNamedAndRemoveUntil('/home', (route) => false);
        break;
      default:
        debugPrint('Unhandled deep link path: ${data.path}');
        _showErrorSnackBar('Unknown link destination');
    }
  }

  void _handleProfileDeepLink(NavigatorState navigator, DeepLinkData data) {
    final profileId = data.segment2;

    if (profileId == null || !DeepLinkValidator.isValidProfileId(profileId)) {
      debugPrint('Invalid profile ID in deep link: $profileId');
      _showErrorSnackBar('Invalid profile link');
      return;
    }

    navigator.pushNamed(
      '/profile',
      arguments: ProfileDeepLinkArgs(
        profileId: profileId,
        source: data.parameters['source'] ?? 'deep_link',
        campaign: data.parameters['campaign'],
      ),
    );
  }

  void _handlePaymentDeepLink(NavigatorState navigator, DeepLinkData data) {
    final action = data.segment2;

    if (action == null || !DeepLinkValidator.isValidPaymentAction(action)) {
      debugPrint('Invalid payment action in deep link: $action');
      _showErrorSnackBar('Invalid payment link');
      return;
    }

    switch (action) {
      case 'confirm':
        final transactionId = data.parameters['txn_id'];
        if (transactionId != null &&
            RegExp(r'^[a-zA-Z0-9_-]{1,64}$').hasMatch(transactionId)) {
          navigator.pushNamed(
            '/payment/confirm',
            arguments: PaymentDeepLinkArgs(
              action: action,
              transactionId: transactionId,
              source: data.parameters['source'] ?? 'deep_link',
            ),
          );
        } else {
          navigator.pushNamed('/payment/confirm');
        }
        break;
      case 'cancel':
        navigator.pushNamed('/payment/cancel',
            arguments: PaymentDeepLinkArgs(
              action: action,
              source: data.parameters['source'] ?? 'deep_link',
            ));
        break;
      case 'status':
        navigator.pushNamed('/payment/status',
            arguments: PaymentDeepLinkArgs(
              action: action,
              transactionId: data.parameters['txn_id'],
              source: data.parameters['source'] ?? 'deep_link',
            ));
        break;
    }
  }

  void _handleSettingsDeepLink(NavigatorState navigator, DeepLinkData data) {
    navigator.pushNamed('/settings');
  }

  void _showErrorSnackBar(String message) {
    final context = navigatorKey.currentContext;
    if (context != null) {
      ScaffoldMessenger.of(context).showSnackBar(
        SnackBar(
          content: Text(message),
          backgroundColor: Colors.red.shade700,
          duration: const Duration(seconds: 3),
        ),
      );
    }
  }

  void dispose() {
    _linkSubscription?.cancel();
  }
}

