// App Route Generator
class AppRouteGenerator {
  static Route<dynamic> generateRoute(RouteSettings settings) {
    switch (settings.name) {
      case '/':
      case '/home':
        return MaterialPageRoute(builder: (_) => const HomeScreen());
      case '/profile':
        return MaterialPageRoute(builder: (_) => const ProfileScreen());
      case '/payment/confirm':
        return MaterialPageRoute(
            builder: (_) => const PaymentConfirmScreen());
      case '/payment/cancel':
        return MaterialPageRoute(
            builder: (_) => const PaymentCancelScreen());
      case '/payment/status':
        return MaterialPageRoute(
            builder: (_) => const PaymentStatusScreen());
      case '/settings':
        return MaterialPageRoute(builder: (_) => const SettingsScreen());
      default:
        return MaterialPageRoute(
          builder: (_) => Scaffold(
            appBar: AppBar(title: const Text('Not Found')),
            body: Center(
              child: Text('Route not found: ${settings.name}'),
            ),
          ),
        );
    }
  }
}

// Main App
class DeepLinkApp extends StatefulWidget {
  const DeepLinkApp({super.key});

  @override
  State<DeepLinkApp> createState() => _DeepLinkAppState();
}

class _DeepLinkAppState extends State<DeepLinkApp> {
  final DeepLinkHandler _deepLinkHandler = DeepLinkHandler();

  @override
  void initState() {
    super.initState();
    _deepLinkHandler.initialize();
  }

  @override
  void dispose() {
    _deepLinkHandler.dispose();
    super.dispose();
  }

  @override
  Widget build(BuildContext context) {
    return MaterialApp(
      title: 'Deep Link Demo',
      navigatorKey: _deepLinkHandler.navigatorKey,
      theme: ThemeData(
        colorSchemeSeed: Colors.blue,
        useMaterial3: true,
      ),
      initialRoute: '/',
      onGenerateRoute: AppRouteGenerator.generateRoute,
    );
  }
}

void main() {
  WidgetsFlutterBinding.ensureInitialized();
  runApp(const DeepLinkApp());
}